query:
SELECT id, CONCAT('[', chaveJ, ']') as chaveJ_raw, LENGTH(chaveJ) as len FROM agentes WHERE chaveJ LIKE '%726228%';
SELECT COUNT(*) as total_agentes FROM agentes;
SELECT COUNT(*) as total_certs FROM certificacoes;
SELECT COUNT(DISTINCT UPPER(TRIM(chaveJ))) as chaves_cert FROM certificacoes WHERE chaveJ IS NOT NULL;

